#!/usr/bin/env python3
"""超级简单的计算器，支持加减乘除。"""


def calculate(a, op, b):
    if op == "+":
        return a + b
    if op == "-":
        return a - b
    if op == "*":
        return a * b
    if op == "/":
        if b == 0:
            raise ZeroDivisionError("除数不能为 0")
        return a / b
    raise ValueError(f"不支持的运算符: {op}")


def main():
    print("简单计算器（支持 + - * /），输入 q 退出")
    while True:
        expr = input("> ").strip()
        if expr.lower() in ("q", "quit", "exit"):
            break
        try:
            a, op, b = expr.split()
            result = calculate(float(a), op, float(b))
            print(result)
        except ZeroDivisionError as e:
            print(e)
        except ValueError:
            print("输入格式有误，请按「数字 运算符 数字」输入，例如：3 + 5")


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""超级简单的计算器，支持加减乘除和括号。"""

import re


def tokenize(expr):
    """把表达式拆成数字、运算符和括号 token。"""
    tokens = re.findall(r"\d+\.?\d*|[+\-*/()]", expr)
    if "".join(tokens) != re.sub(r"\s", "", expr):
        raise ValueError("表达式含有无法识别的字符")
    return tokens


def parse(tokens):
    """递归下降解析并求值，文法：expr -> term (('+'|'-') term)*。"""
    pos = 0

    def peek():
        return tokens[pos] if pos < len(tokens) else None

    def consume():
        nonlocal pos
        tok = tokens[pos]
        pos += 1
        return tok

    def expr():
        value = term()
        while peek() in ("+", "-"):
            op = consume()
            value = value + term() if op == "+" else value - term()
        return value

    def term():
        value = factor()
        while peek() in ("*", "/"):
            op = consume()
            rhs = factor()
            if op == "*":
                value = value * rhs
            else:
                if rhs == 0:
                    raise ZeroDivisionError("除数不能为 0")
                value = value / rhs
        return value

    def factor():
        tok = peek()
        if tok == "(":
            consume()
            value = expr()
            if peek() != ")":
                raise ValueError("括号不匹配")
            consume()
            return value
        if tok == "-":  # 一元负号，如 -3 或 -(1+2)
            consume()
            return -factor()
        if tok is None or not re.fullmatch(r"\d+\.?\d*", tok):
            raise ValueError("表达式格式有误")
        return float(consume())

    result = expr()
    if pos != len(tokens):
        raise ValueError("表达式格式有误")
    return result


def calculate(expr_str):
    return parse(tokenize(expr_str))


def main():
    print("简单计算器（支持 + - * / 和括号），输入 q 退出")
    while True:
        expr_str = input("> ").strip()
        if expr_str.lower() in ("q", "quit", "exit"):
            break
        if not expr_str:
            continue
        try:
            print(calculate(expr_str))
        except ZeroDivisionError as e:
            print(e)
        except ValueError as e:
            print(f"输入有误：{e}")


if __name__ == "__main__":
    main()
